import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import { motion } from 'framer-motion';
import {
  FiCalendar,
  FiUsers,
  FiSettings,
  FiLogOut,
  FiBarChart,
  FiSearch,
  FiList,
  FiGrid,
  FiTable
} from 'react-icons/fi';
import { useAuth } from '../context/AuthContext';
import { Booking, Employee, ContactQuery as BaseContactQuery } from '../types';
import { apiService } from '../services/api';
import { API_ENDPOINTS, getApiUrl } from '../config/api';
import { useQuery } from 'react-query';
import toast from 'react-hot-toast';

type ContactQuery = BaseContactQuery & {
  id?: string;
  admin_response?: string;
  response_date?: string;
  user_id?: string | number;
  customer_name?: string;
  mobile_number?: string;
  created_at_formatted?: string;
  updated_at?: string;
  has_response?: boolean;
  response_date_formatted?: string;
};

// Minimal Modal component for local use
const Modal: React.FC<{ onClose: () => void; children: React.ReactNode }> = ({ onClose, children }) => {
  const [isMobile, setIsMobile] = useState(false);

  useEffect(() => {
    const checkMobile = () => setIsMobile(window.innerWidth < 640);
    checkMobile();
    window.addEventListener('resize', checkMobile);
    return () => window.removeEventListener('resize', checkMobile);
  }, []);

  const modalStyle: React.CSSProperties = isMobile
    ? {
        background: 'white',
        borderRadius: 8,
        padding: 12,
        position: 'relative',
        width: '95vw',
        maxWidth: '95vw',
        minWidth: 0,
        boxSizing: 'border-box',
        maxHeight: '90vh',
        overflowY: 'auto',
      }
    : {
        background: 'white',
        borderRadius: 8,
        padding: 24,
        position: 'relative',
        minWidth: 400,
        maxWidth: 700,
        width: '100%',
        boxSizing: 'border-box',
        maxHeight: '90vh',
        overflowY: 'auto',
      };
  const containerStyle: React.CSSProperties = {
    position: 'fixed',
    top: 0,
    left: 0,
    width: '100vw',
    height: '100vh',
    background: 'rgba(0,0,0,0.3)',
    zIndex: 1000,
    display: 'flex',
    alignItems: 'center',
    justifyContent: 'center',
  };
  return (
    <div style={containerStyle}>
      <div style={modalStyle}>
        <button onClick={onClose} style={{ position: 'absolute', top: 8, right: 12, fontSize: 20, background: 'none', border: 'none', cursor: 'pointer' }}>&times;</button>
        {children}
      </div>
    </div>
  );
};

// Add Service Modal component
const ServiceModal: React.FC<{
  open: boolean;
  onClose: () => void;
  onSave: (service: any) => void;
  initialData?: any;
}> = ({ open, onClose, onSave, initialData }) => {
  // Service meta fields
  const [serviceName, setServiceName] = useState(initialData?.service_name || '');
  const [description, setDescription] = useState(initialData?.description || '');
  const [locations, setLocations] = useState(initialData?.locations || []);
  // Service types and pricing
  const [serviceTypes, setServiceTypes] = useState<any[]>(initialData?.service_types || [
    { typeName: '', pricingFields: [{ roomSize: '', price: '' }] }
  ]);

  useEffect(() => {
    setServiceName(initialData?.service_name || '');
    setDescription(initialData?.description || '');
    setLocations(initialData?.locations || []);
    setServiceTypes(initialData?.service_types || [
      { typeName: '', pricingFields: [{ roomSize: '', price: '' }] }
    ]);
  }, [initialData, open]);

  if (!open) return null;

  // Handlers for service types and pricing fields
  const handleTypeChange = (idx: number, value: string) => {
    setServiceTypes(types => types.map((t, i) => i === idx ? { ...t, typeName: value } : t));
  };
  const handleAddType = () => {
    setServiceTypes(types => [...types, { typeName: '', pricingFields: [{ roomSize: '', price: '' }] }]);
  };
  const handleRemoveType = (idx: number) => {
    setServiceTypes(types => types.filter((_, i) => i !== idx));
  };
  const handlePricingChange = (typeIdx: number, fieldIdx: number, key: string, value: string) => {
    setServiceTypes(types => types.map((t: any, i: number) =>
      i === typeIdx
        ? { ...t, pricingFields: t.pricingFields.map((f: any, j: number) => j === fieldIdx ? { ...f, [key]: value } : f) }
        : t
    ));
  };
  const handleAddPricingField = (typeIdx: number) => {
    setServiceTypes(types => types.map((t: any, i: number) =>
      i === typeIdx
        ? { ...t, pricingFields: [...t.pricingFields, { roomSize: '', price: '' }] }
        : t
    ));
  };
  const handleRemovePricingField = (typeIdx: number, fieldIdx: number) => {
    setServiceTypes(types => types.map((t: any, i: number) =>
      i === typeIdx
        ? { ...t, pricingFields: t.pricingFields.filter((_: any, j: number) => j !== fieldIdx) }
        : t
    ));
  };

  // Summary calculations
  const totalFields = serviceTypes.reduce((sum: number, t: any) => sum + t.pricingFields.length, 0);
  const avgPrice = (() => {
    const prices = serviceTypes.flatMap((t: any) => t.pricingFields.map((f: any) => parseFloat(f.price) || 0));
    if (!prices.length) return 0;
    return Math.round(prices.reduce((a: number, b: number) => a + b, 0) / prices.length);
  })();

  // Save handler
  const handleSave = () => {
    onSave({
      service_name: serviceName,
      description,
      locations,
      service_types: serviceTypes
    });
  };

  return (
    <Modal onClose={onClose}>
      <div className="flex flex-col md:flex-row gap-6">
        {/* Main Form */}
        <div className="flex-1 min-w-0">
          <h2 className="text-lg font-semibold mb-2">{initialData ? 'Edit Service' : 'Add Service'}</h2>
          <div className="mb-3 grid grid-cols-1 md:grid-cols-2 gap-4">
            <div>
              <label className="block text-sm font-medium mb-1">Service Name</label>
              <input className="w-full border rounded p-2" value={serviceName} onChange={e => setServiceName(e.target.value)} />
            </div>
            <div>
              <label className="block text-sm font-medium mb-1">Locations</label>
              <input className="w-full border rounded p-2" value={locations.join(', ')} onChange={e => setLocations(e.target.value.split(',').map(s => s.trim()))} placeholder="Enter locations separated by commas" />
            </div>
          </div>
          <div className="mb-3">
            <label className="block text-sm font-medium mb-1">Description</label>
            <textarea className="w-full border rounded p-2" value={description} onChange={e => setDescription(e.target.value)} />
          </div>
          {/* Service Types & Pricing */}
          <div className="mt-6">
            <h3 className="font-semibold text-base mb-2 flex items-center gap-2">Service Types & Pricing <button className="ml-2 btn btn-primary btn-xs" onClick={handleAddType}>+ Add Service Type</button></h3>
            {serviceTypes.map((type, typeIdx) => (
              <div key={typeIdx} className="mb-6 border rounded-lg p-4 bg-gray-50">
                <div className="flex items-center gap-2 mb-2">
                  <input className="border rounded p-2 flex-1" placeholder="Type Name" value={type.typeName} onChange={e => handleTypeChange(typeIdx, e.target.value)} />
                  {serviceTypes.length > 1 && <button className="btn btn-danger btn-xs" onClick={() => handleRemoveType(typeIdx)}>Delete Type</button>}
                </div>
                <div className="mb-2 font-medium">Pricing Structure</div>
                {type.pricingFields.map((field: any, fieldIdx: number) => (
                  <div key={fieldIdx} className="flex items-center gap-2 mb-2">
                    <input className="border rounded p-2 flex-1" placeholder="Room Size" value={field.roomSize} onChange={e => handlePricingChange(typeIdx, fieldIdx, 'roomSize', e.target.value)} />
                    <input className="border rounded p-2 w-32" placeholder="Price" type="number" value={field.price} onChange={e => handlePricingChange(typeIdx, fieldIdx, 'price', e.target.value)} />
                    {type.pricingFields.length > 1 && <button className="btn btn-danger btn-xs" onClick={() => handleRemovePricingField(typeIdx, fieldIdx)}>Delete</button>}
                  </div>
                ))}
                <button className="btn btn-secondary btn-xs mt-2" onClick={() => handleAddPricingField(typeIdx)}>+ Add Pricing Field</button>
              </div>
            ))}
          </div>
        </div>
        {/* Actions & Summary */}
        <div className="w-full md:w-80 flex-shrink-0 bg-gray-50 rounded-lg p-4 border">
          <div className="mb-4">
            <h4 className="font-semibold mb-2">Summary</h4>
            <div className="text-sm mb-1">Service Types: <b>{serviceTypes.length}</b></div>
            <div className="text-sm mb-1">Total Fields: <b>{totalFields}</b></div>
            <div className="text-sm mb-1">Avg Price: <b>₹{avgPrice}</b></div>
          </div>
          <div className="mb-4">
            <h4 className="font-semibold mb-2">Quick Actions</h4>
            <button className="btn btn-secondary btn-xs mb-2 w-full" onClick={handleAddType}>+ Add Service Type</button>
            {/* Duplicate type, etc. can be added here */}
          </div>
          <div className="flex flex-col gap-2">
            <button className="btn btn-primary" onClick={handleSave}>Save Changes</button>
            <button className="btn btn-secondary" onClick={onClose}>Cancel</button>
          </div>
        </div>
      </div>
    </Modal>
  );
};

const AdminDashboard: React.FC = () => {
  const { user, logout } = useAuth();
  const navigate = useNavigate();
  const [activeTab, setActiveTab] = useState('overview');

  // Modal state for viewing and replying to queries
  const [viewedQuery, setViewedQuery] = useState<ContactQuery | null>(null);
  const [replyingQuery, setReplyingQuery] = useState<ContactQuery | null>(null);
  const [replyText, setReplyText] = useState('');
  const [isReplying, setIsReplying] = useState(false);

  // Modal state for viewing a booking and technician assignment
  const [viewedBooking, setViewedBooking] = useState<any | null>(null);
  const [selectedTechnician, setSelectedTechnician] = useState<string>('');
  const [isAssigning, setIsAssigning] = useState(false);

  // Search and filter state for Contact Queries
  const [querySearch, setQuerySearch] = useState('');
  const [queryStatus, setQueryStatus] = useState('all');

  // View mode for Contact Queries
  const [queryView, setQueryView] = useState<'table' | 'card' | 'list'>('table');

  // Search, filter, and view state for Bookings
  const [bookingSearch, setBookingSearch] = useState('');
  const [bookingStatus, setBookingStatus] = useState('all');
  const [bookingView, setBookingView] = useState<'table' | 'card' | 'list'>('table');

  // Services tab state
  const [activeServiceModal, setActiveServiceModal] = useState<'add' | 'edit' | null>(null);
  const [editingService, setEditingService] = useState<any>(null);
  const [serviceToDelete, setServiceToDelete] = useState<any>(null);
  const [services, setServices] = useState<any[]>([]);
  const [servicesLoading, setServicesLoading] = useState(false);
  const fetchServices = async () => {
    setServicesLoading(true);
    try {
      const res = await apiService.get(API_ENDPOINTS.GET_SERVICE_TYPES);
      if (res.status === 'success' && res.data) {
        setServices(Array.isArray(res.data) ? res.data : []);
      } else {
        setServices([]);
        toast.error(res.message || 'Failed to load services');
      }
    } catch (error: any) {
      console.error('Services fetch error:', error);
      setServices([]);
      toast.error('Failed to load services');
    } finally {
      setServicesLoading(false);
    }
  };
  useEffect(() => { if (activeTab === 'services') fetchServices(); }, [activeTab]);
  const handleAddService = async (service: any) => {
    try {
      // For each service type, add its pricing fields
      for (const serviceType of service.service_types) {
        for (const pricingField of serviceType.pricingFields) {
          await apiService.post(API_ENDPOINTS.ADD_SERVICE_TYPE, {
            service_name: service.service_name,
            service_type_name: serviceType.typeName,
            pricing: [{
              room_size: pricingField.roomSize,
              price: pricingField.price
            }]
          });
        }
      }
      toast.success('Service types added');
      setActiveServiceModal(null);
      fetchServices();
    } catch (error: any) {
      console.error('Add service error:', error);
      toast.error('Failed to add service');
    }
  };
  const handleEditService = async (service: any) => {
    try {
      // Update the specific pricing field
      await apiService.post(API_ENDPOINTS.UPDATE_PRICING_FIELD, {
        pricing_field_id: editingService.selectedField.id,
        room_size: service.selectedField.roomSize,
        price: service.selectedField.price
      });
      toast.success('Pricing field updated');
      setActiveServiceModal(null);
      setEditingService(null);
      fetchServices();
    } catch (error: any) {
      console.error('Edit service error:', error);
      toast.error('Failed to update pricing field');
    }
  };
  const handleDeleteService = async () => {
    try {
      await apiService.post(API_ENDPOINTS.DELETE_PRICING_FIELD, { 
        service_type_id: serviceToDelete.selectedField?.id 
      });
      toast.success('Pricing field deleted');
      setServiceToDelete(null);
      fetchServices();
    } catch (error: any) {
      console.error('Delete error:', error);
      toast.error('Failed to delete pricing field');
    }
  };

  const handleViewQuery = (query: ContactQuery) => {
    setViewedQuery(query);
  };

  const handleReplyQuery = (query: ContactQuery) => {
    setReplyingQuery(query);
    setReplyText('');
  };

  const handleViewBooking = (booking: any) => {
    setViewedBooking(booking);
    setSelectedTechnician(booking.technician_id || '');
  };

  const handleAssignTechnician = async () => {
    if (!viewedBooking || !selectedTechnician) {
      toast.error('Please select a technician');
      return;
    }
    setIsAssigning(true);
    try {
      const res = await apiService.post(getApiUrl(API_ENDPOINTS.ASSIGN_TECHNICIAN), {
        booking_id: viewedBooking.booking_id,
        technician_id: selectedTechnician
      });
      if (res.status === 'success') {
        toast.success('Technician assigned successfully!');
        setViewedBooking(null); // Close the modal
        refetchBookings && refetchBookings(); // Refresh bookings list
      } else {
        toast.error(res.message || 'Failed to assign technician');
      }
    } catch (e: any) {
      toast.error(e.message || 'Network error');
    } finally {
      setIsAssigning(false);
    }
  };

  // Fetch data
  const { data: queriesData, isLoading: queriesLoading, refetch: refetchQueries } = useQuery(
    'contact-queries',
    () => apiService.get<ContactQuery[]>(API_ENDPOINTS.ADMIN_CONTACT_QUERIES),
    {
      retry: 1,
      onError: (error) => {
        toast.error('Failed to load contact queries');
      },
    }
  );

  const handleSubmitReply = async () => {
    if (!replyText.trim() || !replyingQuery) {
      toast.error('Response cannot be empty');
      return;
    }
    setIsReplying(true);
    try {
      const data = await apiService.post(
        getApiUrl(API_ENDPOINTS.ADMIN_CONTACT_QUERIES),
        {
          query_id: replyingQuery.id,
          response: replyText,
          status: 'responded',
        }
      );
      if (data.status === 'success') {
        toast.success('Response submitted successfully!');
        setReplyingQuery(null);
        setReplyText('');
        refetchQueries();
      } else {
        toast.error(data.message || 'Failed to submit response');
      }
    } catch (e: any) {
      toast.error(e.message || 'Network error. Please try again.');
    } finally {
      setIsReplying(false);
    }
  };

  // Fetch data
  const { data: bookingsData, isLoading: bookingsLoading, refetch: refetchBookings } = useQuery(
    'admin-bookings',
    () => apiService.get<Booking[]>(API_ENDPOINTS.ADMIN_ORDERS),
    {
      retry: 1,
      onError: (error) => {
        toast.error('Failed to load bookings');
      },
    }
  );
  const { data: employeesData, isLoading: employeesLoading } = useQuery(
    'employees',
    () => apiService.get<Employee[]>(API_ENDPOINTS.GET_TECHNICIANS),
    {
      retry: 1,
      onError: (error) => {
        toast.error('Failed to load employees');
      },
    }
  );
  const { data: offersData, isLoading: offersLoading } = useQuery(
    'offers',
    () => apiService.get<any>(API_ENDPOINTS.FETCH_OFFERS),
    {
      retry: 1,
      onError: (error) => {
        toast.error('Failed to load offers');
      },
    }
  );

  // Bookings and employees data processing
  const bookingsDataAny = bookingsData as any;
  const bookings = [
    ...(bookingsDataAny?.orders?.pending || []),
    ...(bookingsDataAny?.orders?.completed || []),
    ...(bookingsDataAny?.orders?.accepted || []),
  ].sort((a, b) => new Date(b.service_date).getTime() - new Date(a.service_date).getTime());
  const employeesDataAny = employeesData as any;
  const employees = (employeesDataAny?.data || []).map((emp: any) => ({
    id: emp.technician_id,
    name: emp.employee_name,
    email: emp.email,
    mobile: emp.phone_number,
    serviceType: emp.service_type,
    address: emp.address,
    idProof: emp.id_proof,
  }));
  const queriesDataAny = queriesData as any;
  const queries = queriesDataAny?.queries || queriesDataAny?.data?.queries || [];

  // Stats
  const totalBookings = bookings.length;
  const pendingBookings = bookings.filter(b => b.booking_status === 'pending').length;
  const completedBookings = bookings.filter(b => b.booking_status === 'completed').length;
  const totalRevenue = bookings.reduce((sum, b) => sum + b.total_amount, 0);
  const pendingQueries = queries.filter((q: any) => q.status === 'pending').length;

  const statsCards = [
    {
      title: 'Total Bookings',
      value: totalBookings,
      icon: FiCalendar,
      color: 'bg-blue-500',
    },
    {
      title: 'Pending Bookings',
      value: pendingBookings,
      icon: FiCalendar,
      color: 'bg-yellow-500',
    },
    {
      title: 'Total Revenue',
      value: `₹${totalRevenue.toLocaleString()}`,
      icon: FiCalendar,
      color: 'bg-green-500',
    },
    {
      title: 'Active Employees',
      value: employees.length,
      icon: FiUsers,
      color: 'bg-purple-500',
    },
  ];

  // Navigation items for sidebar
  const navigationItems = [
    { id: 'overview', label: 'Overview', icon: FiBarChart },
    { id: 'bookings', label: 'Bookings', icon: FiCalendar },
    { id: 'employees', label: 'Employees', icon: FiUsers },
    { id: 'services', label: 'Services', icon: FiSettings },
    { id: 'queries', label: 'Contact Queries', icon: FiSettings },
  ];

  // Helper functions
  const getStatusColor = (status: string) => {
    switch (status) {
      case 'completed':
      case 'responded':
        return 'bg-green-100 text-green-800';
      case 'accepted':
      case 'confirmed':
        return 'bg-blue-100 text-blue-800';
      case 'pending':
        return 'bg-yellow-100 text-yellow-800';
      case 'cancelled':
        return 'bg-red-100 text-red-800';
      default:
        return 'bg-gray-100 text-gray-800';
    }
  };
  const formatDate = (dateString: string) => {
    const date = new Date(dateString);
    return date.toLocaleDateString('en-US', {
      year: 'numeric',
      month: 'short',
      day: 'numeric',
    });
  };

  // Main render
  return (
    <div className="min-h-screen bg-gray-50 font-sans flex">
      {/* Sidebar Navigation */}
      <aside className="h-screen w-64 bg-white shadow-lg flex flex-col fixed left-0 top-0 z-30 border-r">
        <div className="h-20 flex items-center px-8 border-b">
          <div className="w-12 h-12 bg-teal-600 rounded-xl flex items-center justify-center mr-4">
            <FiBarChart className="w-7 h-7 text-white" />
          </div>
          <div>
            <h1 className="text-xl font-semibold text-gray-900 tracking-tight">NPC Admin</h1>
            <p className="text-xs text-gray-500 font-medium">Administration Panel</p>
          </div>
        </div>
        <nav className="flex-1 py-8 px-4 space-y-2">
          {[
            { id: 'overview', label: 'Overview', icon: FiBarChart },
            { id: 'bookings', label: 'Bookings', icon: FiCalendar },
            { id: 'employees', label: 'Employees', icon: FiUsers },
            { id: 'services', label: 'Services', icon: FiSettings },
            { id: 'queries', label: 'Contact Queries', icon: FiSettings }
          ].map((tab) => (
            <button
              key={tab.id}
              onClick={() => setActiveTab(tab.id as any)}
              className={`w-full flex items-center gap-3 px-5 py-3 rounded-xl text-base font-medium transition-colors duration-200
                ${activeTab === tab.id
                  ? 'bg-teal-100 text-teal-700 shadow border-l-4 border-teal-500'
                  : 'text-gray-700 hover:bg-gray-100'}
              `}
            >
              <tab.icon className="w-5 h-5" />
              <span>{tab.label}</span>
            </button>
          ))}
        </nav>
        <div className="px-8 py-6 border-t mt-auto bg-white">
          <div className="mb-2">
            <span className="text-sm text-gray-700">Welcome, <span className="font-semibold">{user?.name || 'Admin'}</span></span>
          </div>
          <button
            onClick={logout}
            className="w-full flex items-center justify-center gap-2 py-2 rounded-lg border border-gray-200 text-gray-500 hover:text-red-600 hover:border-red-200 transition-colors font-semibold"
          >
            <FiLogOut className="w-4 h-4" /> Logout
          </button>
        </div>
      </aside>
      {/* Main Content */}
